const nombre = $input.first().json.nombre || 'Desconocido';
const telefono = $input.first().json.telefono || 'No proporcionado';
const mensaje = $input.first().json.mensaje || '';

const prompt = 'Eres un calificador de leads para una agencia de marketing digital en Panama. Analiza este prospecto y responde SOLO con un JSON valido sin markdown con estos campos exactos: calificado (true o false), prioridad (alta, media o baja), razon (string corto), respuesta (mensaje personalizado en espanol para enviarle al lead).\n\nNombre: ' + nombre + '\nTelefono: ' + telefono + '\nMensaje: ' + mensaje;

const bodyString = JSON.stringify({
  contents: [{ parts: [{ text: prompt }] }]
});

return [{ json: { nombre, telefono, mensaje, bodyString } }];

const geminiText = $input.first().json.candidates[0].content.parts[0].text;
let calificacion;
try {
  const clean = geminiText.replace(/```json\n?/g, '').replace(/```/g, '').trim();
  calificacion = JSON.parse(clean);
} catch(e) {
  calificacion = { raw: geminiText };
}

const leadData = $('Preparar Prompt').first().json;

return [{
  json: {
    recibido: true,
    lead: {
      nombre: leadData.nombre,
      telefono: leadData.telefono,
      mensaje: leadData.mensaje
    },
    calificacion,
    timestamp: new Date().toISOString()
  }
}];
